:root {
	--hue: 280;
	--chroma: 0.18;
	--lightness: 0.55;
	--brand: hsl(var(--hue) 60% 55%);
	--hero-gradient: linear-gradient(140deg, #8bb6ff 0%, #ffd2a8 100%);
	--canvas: #f7f8fb;
	--surface: rgba(255, 255, 255, 0.88);
	--surface-elevated: #fff;
	--text-primary: #1f2330;
	--text-secondary: #5e6678;
	--border: rgba(29, 38, 66, 0.15);
	--brand-hover: hsl(var(--hue) 62% 62%);
	--brand-active: hsl(var(--hue) 62% 48%);
	--brand-muted: hsl(var(--hue) 25% 56%);
	--brand-translucent: hsla(var(--hue) 60% 55% / 0.14);
	--brand-shadow: hsla(var(--hue) 30% 20% / 0.25);
	--brand-complement: hsl(calc(var(--hue) + 180) 60% 55%);
	--brand-triadic-1: hsl(calc(var(--hue) + 120) 60% 55%);
	--brand-triadic-2: hsl(calc(var(--hue) + 240) 60% 55%);
	color-scheme: light dark;
}
:root[data-theme="dark"] {
	--canvas: #1b2330;
	--surface: rgba(35, 46, 64, 0.88);
	--surface-elevated: #253147;
	--text-primary: #e8eef9;
	--text-secondary: #b0bdd4;
	--border: rgba(164, 184, 224, 0.22);
	--hero-gradient: linear-gradient(140deg, #3b567d 0%, #6b5a49 100%);
}

@supports (color: oklch(50% 0.1 240)) {
	:root {
		--brand: oklch(var(--lightness) var(--chroma) var(--hue));
		--hero-gradient: linear-gradient(
			140deg in oklab,
			oklch(70% 0.35 var(--hue)) 0%,
			oklch(90% 0.25 calc(var(--hue) - 140)) 100%
		);
		--brand-hover: oklch(from var(--brand) calc(l + 0.08) c h);
		--brand-active: oklch(from var(--brand) calc(l - 0.05) c h);
		--brand-muted: oklch(from var(--brand) l calc(c * 0.5) h);
		--brand-translucent: oklch(from var(--brand) l c h / 0.12);
		--brand-shadow: oklch(from var(--brand) 0.15 0.1 h / 0.25);
		--brand-complement: oklch(from var(--brand) l c calc(h + 180));
		--brand-triadic-1: oklch(from var(--brand) l c calc(h + 120));
		--brand-triadic-2: oklch(from var(--brand) l c calc(h + 240));
	}
}

* {
	box-sizing: border-box;
	margin: 0;
	padding: 0;
}
@media (prefers-reduced-motion: reduce) {
	*,
	*::before,
	*::after {
		animation-duration: 0.01ms !important;
		animation-iteration-count: 1 !important;
		transition-duration: 0.01ms !important;
		scroll-behavior: auto !important;
	}
}
body {
	background: var(--hero-gradient);
	min-height: 100vh;
	display: grid;
	place-items: center;
	padding: clamp(1rem, 4vw, 3rem);
	font-family: "IBM Plex Sans", "Segoe UI", system-ui, sans-serif;
	color: var(--text-primary);
}
.app-shell {
	width: min(1200px, 100%);
	background: var(--canvas);
	border: 1px solid var(--border);
	border-radius: 32px;
	padding: clamp(1.5rem, 4vw, 4rem);
	box-shadow: 0 40px 80px -30px var(--brand-shadow);
}
header {
	display: flex;
	justify-content: space-between;
	align-items: center;
	flex-wrap: wrap;
	gap: 1rem;
	padding-bottom: 1.5rem;
	margin-bottom: 2rem;
	border-bottom: 1px solid var(--border);
}
.logo h1 {
	font-size: clamp(1.2rem, 3vw, 2rem);
	font-weight: 800;
	letter-spacing: -0.03em;
}
.logo span {
	display: block;
	font-size: 0.75rem;
	text-transform: uppercase;
	letter-spacing: 0.08em;
	color: var(--text-secondary);
}
.controls {
	display: flex;
	gap: 1rem;
	align-items: center;
	flex-wrap: wrap;
}
.control-group {
	display: flex;
	flex-direction: column;
	gap: 0.25rem;
}
.control-group label {
	font-size: 0.7rem;
	color: var(--text-secondary);
	font-weight: 700;
}
input[type="range"] {
	width: 130px;
	accent-color: var(--brand);
}
.theme-toggle {
	display: flex;
	border: 1px solid var(--border);
	border-radius: 999px;
	padding: 4px;
}
.theme-btn {
	border: 0;
	background: transparent;
	padding: 0.45rem 0.9rem;
	border-radius: 999px;
	cursor: pointer;
	color: var(--text-secondary);
	font-weight: 700;
}
.theme-btn.active {
	background: var(--brand);
	color: #fff;
}
.theme-btn:focus-visible,
input[type="range"]:focus-visible,
.btn-primary:focus-visible,
.social-links a:focus-visible {
	outline: 2px solid var(--brand);
	outline-offset: 2px;
}
.bento-grid {
	display: grid;
	grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
	gap: 1.25rem;
}
.card {
	background: var(--surface);
	border: 1px solid var(--border);
	border-radius: 20px;
	padding: 1.5rem;
}
.card-badge {
	display: inline-block;
	margin-bottom: 0.75rem;
	font-size: 0.65rem;
	font-weight: 800;
	text-transform: uppercase;
	letter-spacing: 0.08em;
	color: var(--brand);
}
.card h3 {
	margin-bottom: 0.5rem;
}
.card p {
	color: var(--text-secondary);
	font-size: 0.9rem;
	margin-bottom: 1rem;
}
.oklch-scale {
	display: flex;
	height: 48px;
	border-radius: 12px;
	overflow: hidden;
}
.scale-step {
	flex: 1;
}
.s1 {
	background: color-mix(in srgb, var(--brand), white 80%);
}
.s2 {
	background: color-mix(in srgb, var(--brand), white 40%);
}
.s3 {
	background: var(--brand);
}
.s4 {
	background: color-mix(in srgb, var(--brand), black 30%);
}
.s5 {
	background: color-mix(in srgb, var(--brand), black 60%);
}
.state-demo {
	display: flex;
	flex-wrap: wrap;
	gap: 0.5rem;
}
.state-chip {
	padding: 0.5rem 0.8rem;
	border-radius: 10px;
	color: #fff;
	font-size: 0.75rem;
}
.chip-base {
	background: var(--brand);
}
.chip-hover {
	background: var(--brand-hover);
}
.chip-active {
	background: var(--brand-active);
}
.chip-muted {
	background: var(--brand-muted);
}
.harmony-wheel {
	display: flex;
	gap: 0.6rem;
}
.harmony-swatch {
	width: 46px;
	height: 46px;
	border-radius: 50%;
	border: 3px solid var(--surface-elevated);
}
.swatch-primary {
	background: var(--brand);
}
.swatch-complement {
	background: var(--brand-complement);
}
.swatch-triadic-1 {
	background: var(--brand-triadic-1);
}
.swatch-triadic-2 {
	background: var(--brand-triadic-2);
}
.auto-contrast {
	background: var(--brand);
	color: #000;
	padding: 1rem;
	border-radius: 12px;
	font-weight: 800;
	text-align: center;
}
.gradient-preview {
	height: 72px;
	border-radius: 12px;
	background: var(--hero-gradient);
}
.btn-primary {
	border: 0;
	border-radius: 12px;
	background: var(--brand);
	color: #fff;
	padding: 0.75rem 1.2rem;
	font-weight: 700;
}
.tech-brief {
	margin-top: 1.5rem;
	padding: 1.25rem;
	border: 1px solid var(--border);
	border-radius: 14px;
	background: var(--surface-elevated);
}
.tech-brief h4 {
	font-size: 0.78rem;
	margin-bottom: 0.65rem;
	text-transform: uppercase;
	letter-spacing: 0.08em;
	color: var(--brand);
}
.tech-brief p {
	font-size: 0.88rem;
	color: var(--text-secondary);
}
footer {
	margin-top: 2rem;
	padding-top: 1rem;
	border-top: 1px solid var(--border);
}
.author {
	margin-bottom: 0.75rem;
	color: var(--text-secondary);
	font-size: 0.86rem;
}
.social-links {
	list-style: none;
	display: flex;
	gap: 1rem;
	flex-wrap: wrap;
}
.social-links a {
	text-decoration: none;
	color: var(--text-secondary);
}
.social-links a:hover {
	color: var(--brand);
}
@media (max-width: 840px) {
	header {
		align-items: flex-start;
		flex-direction: column;
	}
	.controls {
		width: 100%;
	}
}
